(window.webpackJsonp=window.webpackJsonp||[]).push([[875],{832:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[]}</span> <span class=\\"hljs-variable\\">nums1</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[]}</span> <span class=\\"hljs-variable\\">nums2</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> numTriplets = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">nums1, nums2</span>) </span>{\\n    <span class=\\"hljs-keyword\\">let</span> hash1={}\\n    <span class=\\"hljs-keyword\\">let</span> hash2={}\\n    <span class=\\"hljs-keyword\\">let</span> used1={}\\n    <span class=\\"hljs-keyword\\">let</span> used2={}\\n    <span class=\\"hljs-keyword\\">let</span> aux1=[],aux2=[]\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;nums1.length;i++){\\n        <span class=\\"hljs-keyword\\">if</span>(hash1[nums1[i]]==<span class=\\"hljs-literal\\">null</span>){\\n            hash1[nums1[i]]=[nums1[i],<span class=\\"hljs-number\\">1</span>]\\n        }<span class=\\"hljs-keyword\\">else</span>{\\n            hash1[nums1[i]][<span class=\\"hljs-number\\">1</span>]++\\n        }\\n    }\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;nums2.length;i++){\\n        <span class=\\"hljs-keyword\\">if</span>(hash2[nums2[i]]==<span class=\\"hljs-literal\\">null</span>){\\n            hash2[nums2[i]]=[nums2[i],<span class=\\"hljs-number\\">1</span>]\\n        }<span class=\\"hljs-keyword\\">else</span>{\\n            hash2[nums2[i]][<span class=\\"hljs-number\\">1</span>]++\\n        }\\n    }\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> k <span class=\\"hljs-keyword\\">in</span> hash1){\\n        aux1.push(hash1[k])\\n    }\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> k <span class=\\"hljs-keyword\\">in</span> hash2){\\n        aux2.push(hash2[k])\\n    }\\n    aux1.sort(<span class=\\"hljs-function\\">(<span class=\\"hljs-params\\">a,b</span>)=&gt;</span>a[<span class=\\"hljs-number\\">0</span>]-b[<span class=\\"hljs-number\\">0</span>])\\n    aux2.sort(<span class=\\"hljs-function\\">(<span class=\\"hljs-params\\">a,b</span>)=&gt;</span>a[<span class=\\"hljs-number\\">0</span>]-b[<span class=\\"hljs-number\\">0</span>])\\n    <span class=\\"hljs-keyword\\">let</span> res=<span class=\\"hljs-number\\">0</span>\\n    <span class=\\"hljs-comment\\">// console.log(aux1,aux2)</span>\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;aux1.length;i++){\\n        <span class=\\"hljs-keyword\\">let</span> [l,repeL]=aux1[i]\\n        <span class=\\"hljs-keyword\\">let</span> count=<span class=\\"hljs-number\\">0</span>\\n        <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> j=<span class=\\"hljs-number\\">0</span>;j&lt;aux2.length;j++){\\n            <span class=\\"hljs-keyword\\">let</span> [r,repeR]=aux2[j]\\n            <span class=\\"hljs-keyword\\">if</span>(r&gt;l)<span class=\\"hljs-keyword\\">break</span>\\n            <span class=\\"hljs-keyword\\">let</span> nxtNeed=l*l/r\\n            <span class=\\"hljs-keyword\\">if</span>(nxtNeed===r){\\n                count+=getCalc(repeR)\\n            }<span class=\\"hljs-keyword\\">else</span>{\\n                <span class=\\"hljs-keyword\\">if</span>(hash2[nxtNeed]){\\n                     count+=(hash2[nxtNeed][<span class=\\"hljs-number\\">1</span>]*repeR)\\n                }\\n               \\n            }\\n        }\\n        res+=count*repeL\\n    }\\n    <span class=\\"hljs-comment\\">// console.log(\'----\')</span>\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;aux2.length;i++){\\n        <span class=\\"hljs-keyword\\">let</span> [l,repeL]=aux2[i]\\n        <span class=\\"hljs-keyword\\">let</span> count=<span class=\\"hljs-number\\">0</span>\\n        <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> j=<span class=\\"hljs-number\\">0</span>;j&lt;aux1.length;j++){\\n            <span class=\\"hljs-keyword\\">let</span> [r,repeR]=aux1[j]\\n            <span class=\\"hljs-keyword\\">if</span>(r&gt;l)<span class=\\"hljs-keyword\\">break</span>\\n            <span class=\\"hljs-keyword\\">let</span> nxtNeed=l*l/r\\n            <span class=\\"hljs-keyword\\">if</span>(nxtNeed===r){\\n                count+=getCalc(repeR)\\n            }<span class=\\"hljs-keyword\\">else</span>{\\n                <span class=\\"hljs-keyword\\">if</span>(hash1[nxtNeed]){\\n                     count+=(hash1[nxtNeed][<span class=\\"hljs-number\\">1</span>]*repeR)\\n                }\\n               \\n            }\\n        }\\n        <span class=\\"hljs-comment\\">// console.log(count)</span>\\n        res+=count*repeL\\n    }\\n    \\n    <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">getCalc</span>(<span class=\\"hljs-params\\">n</span>)</span>{\\n        <span class=\\"hljs-keyword\\">let</span> res=<span class=\\"hljs-number\\">0</span>\\n        <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">1</span>;i&lt;n;i++){\\n            res+=i\\n        }\\n        <span class=\\"hljs-keyword\\">return</span> res\\n    }\\n    <span class=\\"hljs-keyword\\">return</span> res\\n};\\n</code></pre>\\n"],"titleSlug":"number-of-ways-where-square-of-number-is-equal-to-product-of-two-numbers","hasThinking":false,"content":"<p>\u7ed9\u4f60\u4e24\u4e2a\u6574\u6570\u6570\u7ec4 <code>nums1</code> \u548c <code>nums2</code> \uff0c\u8bf7\u4f60\u8fd4\u56de\u6839\u636e\u4ee5\u4e0b\u89c4\u5219\u5f62\u6210\u7684\u4e09\u5143\u7ec4\u7684\u6570\u76ee\uff08\u7c7b\u578b 1 \u548c\u7c7b\u578b 2 \uff09\uff1a</p>\\n\\n<ul>\\n\\t<li>\u7c7b\u578b 1\uff1a\u4e09\u5143\u7ec4 <code>(i, j, k)</code> \uff0c\u5982\u679c <code>nums1[i]<sup>2</sup>&nbsp;== nums2[j] * nums2[k]</code> \u5176\u4e2d <code>0 &lt;= i &lt; nums1.length</code> \u4e14 <code>0 &lt;= j &lt; k &lt; nums2.length</code></li>\\n\\t<li>\u7c7b\u578b 2\uff1a\u4e09\u5143\u7ec4 <code>(i, j, k)</code> \uff0c\u5982\u679c <code>nums2[i]<sup>2</sup>&nbsp;== nums1[j] * nums1[k]</code> \u5176\u4e2d <code>0 &lt;= i &lt; nums2.length</code> \u4e14 <code>0 &lt;= j &lt; k &lt; nums1.length</code></li>\\n</ul>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>nums1 = [7,4], nums2 = [5,2,8,9]\\n<strong>\u8f93\u51fa\uff1a</strong>1\\n<strong>\u89e3\u91ca\uff1a</strong>\u7c7b\u578b 1\uff1a(1,1,2), nums1[1]^2 = nums2[1] * nums2[2] (4^2 = 2 * 8)</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>nums1 = [1,1], nums2 = [1,1,1]\\n<strong>\u8f93\u51fa\uff1a</strong>9\\n<strong>\u89e3\u91ca\uff1a</strong>\u6240\u6709\u4e09\u5143\u7ec4\u90fd\u7b26\u5408\u9898\u76ee\u8981\u6c42\uff0c\u56e0\u4e3a 1^2 = 1 * 1\\n\u7c7b\u578b 1\uff1a(0,0,1), (0,0,2), (0,1,2), (1,0,1), (1,0,2), (1,1,2), nums1[i]^2 = nums2[j] * nums2[k]\\n\u7c7b\u578b 2\uff1a(0,0,1), (1,0,1), (2,0,1), nums2[i]^2 = nums1[j] * nums1[k]\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>nums1 = [7,7,8,3], nums2 = [1,2,9,7]\\n<strong>\u8f93\u51fa\uff1a</strong>2\\n<strong>\u89e3\u91ca\uff1a</strong>\u6709\u4e24\u4e2a\u7b26\u5408\u9898\u76ee\u8981\u6c42\u7684\u4e09\u5143\u7ec4\\n\u7c7b\u578b 1\uff1a(3,0,2), nums1[3]^2 = nums2[0] * nums2[2]\\n\u7c7b\u578b 2\uff1a(3,0,1), nums2[3]^2 = nums1[0] * nums1[1]\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 4\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>nums1 = [4,7,9,11,23], nums2 = [3,5,1024,12,18]\\n<strong>\u8f93\u51fa\uff1a</strong>0\\n<strong>\u89e3\u91ca\uff1a</strong>\u4e0d\u5b58\u5728\u7b26\u5408\u9898\u76ee\u8981\u6c42\u7684\u4e09\u5143\u7ec4\\n</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>1 &lt;= nums1.length, nums2.length &lt;= 1000</code></li>\\n\\t<li><code>1 &lt;= nums1[i], nums2[i] &lt;= 10^5</code></li>\\n</ul>\\n","title":"1577. \u6570\u7684\u5e73\u65b9\u7b49\u4e8e\u4e24\u6570\u4e58\u79ef\u7684\u65b9\u6cd5\u6570","relatedTags":["\u54c8\u5e0c\u8868","\u6570\u5b66"],"difficult":"Middle","lang":["javascript"],"uniqueID":"1577"}')}}]);